import{_ as r,o as t,c as a,a3 as l}from"./chunks/framework.C49Ar5GK.js";const f=JSON.parse('{"title":"术语、源码锚点与一手资料","description":"veRL V1 术语表、固定提交源码入口、强化学习原论文与 Ray/Hydra/推理系统官方资料","frontmatter":{"title":"术语、源码锚点与一手资料","description":"veRL V1 术语表、固定提交源码入口、强化学习原论文与 Ray/Hydra/推理系统官方资料","lesson":{"stage":"附录","order":24,"time":"按需查阅","level":"参考","question":"遇到版本、公式或系统细节争议时，应该回到哪一份一手证据？"}},"headers":[],"relativePath":"appendix/references.md","filePath":"appendix/references.md","lastUpdated":null}'),o={name:"appendix/references.md"};function i(d,e,n,c,s,p){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="术语、源码锚点与一手资料" tabindex="-1">术语、源码锚点与一手资料 <a class="header-anchor" href="#术语、源码锚点与一手资料" aria-label="Permalink to &quot;术语、源码锚点与一手资料&quot;">​</a></h1><p>本站是课程，不替代源码、测试、官方文档和论文。框架事实优先以固定提交 <code>e5687fce0516d31e1fdc4580499074a9bd94c751</code> 为准；论文用于解释方法假设；运行时行为还需用你的 resolved config、依赖版本和最小实验确认。</p><h2 id="术语速查" tabindex="-1">术语速查 <a class="header-anchor" href="#术语速查" aria-label="Permalink to &quot;术语速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>本站中的准确含义</th></tr></thead><tbody><tr><td>rollout</td><td>用行为策略/LLM server 对 prompt 逐 token 生成一条或多条 trajectory</td></tr><tr><td>trajectory</td><td>prompt、response、mask、概率、reward 与环境/版本元数据组成的轨迹</td></tr><tr><td>actor / policy</td><td>被优化的策略模型角色；不要与 Ray actor 混淆</td></tr><tr><td>rollout engine</td><td>为训练收集轨迹的推理系统，可使用 actor 权重但具有独立运行形态</td></tr><tr><td>reference</td><td>冻结策略，用于 KL 锚定；按配置可省略</td></tr><tr><td>critic</td><td>预测 value 的模型/角色；GRPO 等配方通常可省略</td></tr><tr><td>reward manager</td><td>把 response 与 ground truth/模型/环境反馈转成 score</td></tr><tr><td>return</td><td>从当前位置起的折扣累计奖励</td></tr><tr><td>advantage</td><td>动作/轨迹相对 baseline 好多少的策略更新信号</td></tr><tr><td>old policy</td><td>本轮更新的稳定概率参照，不应自动等同 rollout/reference</td></tr><tr><td>staleness</td><td>生成轨迹的权重版本与当前训练版本之间的延迟</td></tr><tr><td>TQ</td><td>TransferQueue，V1 的 trajectory KV 数据通道</td></tr><tr><td>KVBatchMeta</td><td>携带 partition、keys、tags 的轻量批次句柄，不是完整值本体</td></tr><tr><td>TensorDict</td><td>按 batch 维组织 tensor/non-tensor 字段的容器</td></tr><tr><td>DataProto</td><td>veRL 批协议；V0 主干，V1 在共享算法/接口边界仍使用</td></tr><tr><td>WorkerGroup</td><td>对一组 Ray worker/rank 统一分发计算的控制抽象</td></tr><tr><td>Ray actor</td><td>有状态远程 worker 进程抽象，不等于 RL actor policy</td></tr></tbody></table><h2 id="固定提交的源码入口" tabindex="-1">固定提交的源码入口 <a class="header-anchor" href="#固定提交的源码入口" aria-label="Permalink to &quot;固定提交的源码入口&quot;">​</a></h2><ul><li><a href="https://github.com/verl-project/verl/tree/e5687fce0516d31e1fdc4580499074a9bd94c751" target="_blank" rel="noreferrer">veRL <code>e5687fce</code> 完整树</a></li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/trainer/main_ppo.py" target="_blank" rel="noreferrer"><code>main_ppo.py</code></a>：Hydra、Ray、TaskRunnerV1 入口</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/trainer/config/ppo_trainer.yaml" target="_blank" rel="noreferrer"><code>ppo_trainer.yaml</code></a>：默认 V1、mode、TransferQueue 与全局配置</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/trainer/ppo/v1/trainer_base.py" target="_blank" rel="noreferrer"><code>trainer_base.py</code></a>：V1 init/fit/step、字段读写与扩展 hooks</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/trainer/ppo/v1/trainer_sync.py" target="_blank" rel="noreferrer"><code>trainer_sync.py</code></a>：同步模式权重与 rollout 生命周期</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/trainer/ppo/v1/agent_loop_tq.py" target="_blank" rel="noreferrer"><code>agent_loop_tq.py</code></a>：AgentLoop output 写入 TQ</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/trainer/ppo/v1/replay_buffer.py" target="_blank" rel="noreferrer"><code>replay_buffer.py</code></a>：prompt group、采样与 staleness</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/trainer/ppo/core_algos.py" target="_blank" rel="noreferrer"><code>core_algos.py</code></a>：advantage/policy loss registry 与公式实现</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/experimental/agent_loop/agent_loop.py" target="_blank" rel="noreferrer"><code>agent_loop.py</code></a>：AgentLoopBase/Manager 与多轮生成</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/experimental/reward_loop/reward_loop.py" target="_blank" rel="noreferrer"><code>reward_loop.py</code></a>：并发 reward 计算组织</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/protocol.py" target="_blank" rel="noreferrer"><code>protocol.py</code></a>：DataProto/dispatch 协议</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/utils/dataset/rl_dataset.py" target="_blank" rel="noreferrer"><code>rl_dataset.py</code></a>：数据读取与 chat/token 契约</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/tests/trainer/ppo/test_core_algos_on_cpu.py" target="_blank" rel="noreferrer"><code>test_core_algos_on_cpu.py</code></a>：算法 registry 与 estimator CPU 测试范式</li><li><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/tests/trainer/ppo/v1/test_replay_buffer_on_cpu.py" target="_blank" rel="noreferrer"><code>test_replay_buffer_on_cpu.py</code></a>：V1 sampler 行为证据</li></ul><h2 id="verl-官方文档" tabindex="-1">veRL 官方文档 <a class="header-anchor" href="#verl-官方文档" aria-label="Permalink to &quot;veRL 官方文档&quot;">​</a></h2><p>官方 <code>latest</code> 会继续演进，可能晚于本站绑定提交。用它理解设计和现行建议，再回固定源码核对类名/字段。</p><ul><li><a href="https://verl.readthedocs.io/" target="_blank" rel="noreferrer">veRL 官方文档首页</a></li><li><a href="https://verl.readthedocs.io/en/latest/start/quickstart.html" target="_blank" rel="noreferrer">PPO on GSM8K quickstart</a>：官方数据准备与首个训练入口</li><li><a href="https://verl.readthedocs.io/en/latest/extend_guide.html" target="_blank" rel="noreferrer">How to Extend veRL</a>：reward、tool、AgentLoop、ReplayBuffer、manager 与后端扩展</li><li><a href="https://verl.readthedocs.io/en/latest/advance/agent_loop.html" target="_blank" rel="noreferrer">Agent Loop</a>：多轮/TITO 设计与 server 调用</li><li><a href="https://verl.readthedocs.io/en/latest/advance/reward_loop.html" target="_blank" rel="noreferrer">Reward Loop</a>：分布式与混合 reward 设计</li><li><a href="https://verl.readthedocs.io/en/latest/data/transfer_queue.html" target="_blank" rel="noreferrer">TransferQueue Data System</a>：V1 数据通道背景</li><li><a href="https://verl.readthedocs.io/en/latest/examples/config.html" target="_blank" rel="noreferrer">Config Explanation</a>：配置字段参考</li><li><a href="https://verl.readthedocs.io/en/latest/perf/perf_tuning.html" target="_blank" rel="noreferrer">Performance Tuning Guide</a>：动态 batch、并行与显存/吞吐优化建议</li><li><a href="https://verl.readthedocs.io/en/latest/perf/verl_profiler_system.html" target="_blank" rel="noreferrer">veRL Profiler System</a>：全局/角色级 profiler 配置与扩展方式</li></ul><h2 id="强化学习与系统论文" tabindex="-1">强化学习与系统论文 <a class="header-anchor" href="#强化学习与系统论文" aria-label="Permalink to &quot;强化学习与系统论文&quot;">​</a></h2><h3 id="核心方法" tabindex="-1">核心方法 <a class="header-anchor" href="#核心方法" aria-label="Permalink to &quot;核心方法&quot;">​</a></h3><ul><li><a href="https://arxiv.org/abs/1707.06347" target="_blank" rel="noreferrer">Proximal Policy Optimization Algorithms</a>：PPO surrogate/update 动机</li><li><a href="https://arxiv.org/abs/1506.02438" target="_blank" rel="noreferrer">Generalized Advantage Estimation</a>：GAE 的 bias/variance 折中</li><li><a href="https://arxiv.org/abs/2402.03300" target="_blank" rel="noreferrer">DeepSeekMath</a>：GRPO 与数学推理训练</li><li><a href="https://arxiv.org/abs/2503.20783" target="_blank" rel="noreferrer">Understanding R1-Zero-Like Training</a>：Dr.GRPO、长度与归一化偏差分析</li><li><a href="https://arxiv.org/abs/2503.14476" target="_blank" rel="noreferrer">DAPO</a>：decoupled clip、dynamic sampling、token-level loss、overlong shaping recipe</li><li><a href="https://arxiv.org/abs/2402.14740" target="_blank" rel="noreferrer">Back to Basics / RLOO</a>：leave-one-out baseline 的 RLHF 分析</li></ul><h3 id="框架与推理系统" tabindex="-1">框架与推理系统 <a class="header-anchor" href="#框架与推理系统" aria-label="Permalink to &quot;框架与推理系统&quot;">​</a></h3><ul><li><a href="https://arxiv.org/abs/2409.19256" target="_blank" rel="noreferrer">HybridFlow: A Flexible and Efficient RLHF Framework</a>：veRL 的 hybrid controller/dataflow 设计来源</li><li><a href="https://arxiv.org/abs/2309.06180" target="_blank" rel="noreferrer">PagedAttention / vLLM</a>：动态 KV cache 管理与高吞吐 serving</li></ul><p>论文公式与框架实现不应机械逐行相同。检查它属于 advantage、reward、sampling、policy loss 还是 system 层，再判断是等价改写、工程近似、可选 recipe 或版本变化。</p><h2 id="分布式与配置的一手文档" tabindex="-1">分布式与配置的一手文档 <a class="header-anchor" href="#分布式与配置的一手文档" aria-label="Permalink to &quot;分布式与配置的一手文档&quot;">​</a></h2><ul><li><a href="https://docs.ray.io/en/latest/ray-core/key-concepts.html" target="_blank" rel="noreferrer">Ray Core key concepts</a>：task、actor、object 和资源的官方定义</li><li><a href="https://docs.ray.io/en/latest/ray-core/actors.html" target="_blank" rel="noreferrer">Ray actors</a>：有状态 worker 与故障语义</li><li><a href="https://docs.ray.io/en/latest/ray-core/scheduling/resources.html" target="_blank" rel="noreferrer">Ray logical resources</a>：CPU/GPU resource request 与调度</li><li><a href="https://docs.ray.io/en/latest/ray-observability/getting-started.html" target="_blank" rel="noreferrer">Ray Dashboard</a>：job/task/actor/log/metrics 观测</li><li><a href="https://hydra.cc/docs/advanced/defaults_list/" target="_blank" rel="noreferrer">Hydra Defaults List</a>：组合顺序、override 与 <code>_self_</code></li><li><a href="https://hydra.cc/docs/advanced/terminology/" target="_blank" rel="noreferrer">Hydra terminology / overrides</a>：CLI override 与配置树</li></ul><p>技术实现问题优先引用这些官方文档，而不是不带版本的二手博客；但 veRL 如何使用 Ray/Hydra，仍以当前源码和 resolved config 为最终证据。</p><h2 id="怎样处理资料冲突" tabindex="-1">怎样处理资料冲突 <a class="header-anchor" href="#怎样处理资料冲突" aria-label="Permalink to &quot;怎样处理资料冲突&quot;">​</a></h2><p>按以下顺序：</p><ol><li>打印实际导入路径、commit 与 dirty diff；</li><li>保存 resolved config 与依赖版本；</li><li>在固定提交源码和测试中定位行为；</li><li>用官方文档理解接口设计与版本迁移；</li><li>用原论文核对方法假设和公式；</li><li>写一个 tiny input/one-step 实验确认运行行为。</li></ol><p>“文档说”“论文说”“代码里有这个类”都不是单独充分证据；必须先对齐版本与配置。</p><h2 id="本课程的内容边界" tabindex="-1">本课程的内容边界 <a class="header-anchor" href="#本课程的内容边界" aria-label="Permalink to &quot;本课程的内容边界&quot;">​</a></h2><p>课程重点是默认 V1 的 PPO/GRPO 学习闭环，没有穷举所有模型 engine、rollout backend、多模态、蒸馏、完全异步 recipe 和硬件组合。以下情况必须回源码/测试重新建契约：</p><ul><li>改用 <code>trainer.use_v1=false</code>；</li><li>自定义 AgentLoop/Manager、ReplayBuffer、RewardManager；</li><li>使用非默认 policy loss、rollout correction 或新 estimator；</li><li>使用 Megatron/VeOmni/TorchTitan、MoE、NPU 或多机 RDMA；</li><li>升级 commit 后入口、字段、配置默认值或后端 API 改变。</li></ul><p>发现本站与绑定提交不一致时，以可执行测试和源码为准；修正文档时同时记录旧/新 commit 与行为差异。</p>',26)])])}const b=r(o,[["render",i]]);export{f as __pageData,b as default};
